const members = [
  { id: "steve-johnston", name: "Dad Steve Johnston", title: "Executive Officer", email: "executive.officer@azdemolay.org" },
  { id: "don-lowery", name: "Dad Don Lowery", title: "State Dad", email: "state.officer.director@azdemolay.org" },
  { id: "bill-enloe", name: "Dad Bill Enloe", title: "State Membership Advisor", email: "membership.advisor@azdemolay.org" },
  { id: "seth-baldwin", name: "SMC Seth Baldwin", title: "State Master Councilor", email: "smc@azdemolay.org" },
  { id: "kaden-hartley", name: "DSMC Kaden Hartley", title: "Deputy State Master Councilor", email: "dsmc@azdemolay.org" },
  { id: "cooper-pitman", name: "SSC Cooper Pitman", title: "State Senior Councilor", email: "ssc@azdemolay.org" },
  { id: "john-enloe", name: "SJC John Enloe", title: "State Junior Councilor", email: "sjc@azdemolay.org" },
  { id: "james-hendrickson", name: "Scribe James Hendrickson", title: "State Scribe", email: "scribe@azdemolay.org" },
];

const DAD_EMAILS = ["state.officer.director@azdemolay.org", "state.dad@azdemolay.org", "membership.advisor@azdemolay.org"];

export default function Results() {
  const [auth, setAuth] = useState<any>(null);
  const [reviews, setReviews] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { checkAuth(); }, []);

  const checkAuth = async () => {
    const token = localStorage.getItem("reviewToken");
    if (!token) { window.location.href = "/"; return; }
    try {
      const res = await fetch("/api/auth/me", { headers: { "X-Review-Token": token } });
      const data = await res.json();
      if (data.authenticated) { setAuth(data); loadReviews(token); }
      else { localStorage.removeItem("reviewToken"); window.location.href = "/"; }
    } catch { window.location.href = "/"; }
  };

  const loadReviews = async (token: string) => {
    try {
      const res = await fetch("/api/reviews/export", { headers: { "X-Review-Token": token } });
      const data = await res.json();
      if (data.reviews) setReviews(data.reviews);
    } catch {}
    setLoading(false);
  };

  const handleLogout = () => {
    localStorage.removeItem("reviewToken");
    window.location.href = "https://accounts.google.com/logout";
  };

  const average = (nums: number[]) => nums.length ? (nums.reduce((a, b) => a + b, 0) / nums.length).toFixed(1) : "0.0";

  const getAveragesByMember = () => members.map(m => {
    const memberReviews = reviews.filter(r => r.memberId === m.id);
    const attrKeys = ["leadership", "teamwork", "attendance", "punctuality", "motivation", "ritualWork", "initiative", "planning"];
    const avgs: any = {};
    attrKeys.forEach(k => { avgs[k] = parseFloat(average(memberReviews.map((r: any) => r.ratings[k]))); });
    avgs.overall = parseFloat(average(attrKeys.map((k: string) => avgs[k])));
    avgs.count = memberReviews.length;
    return { ...m, ...avgs };
  });

  const isDad = DAD_EMAILS.includes((auth?.email || "").toLowerCase());

  if (!auth || loading) return (
    <div className="min-h-screen flex items-center justify-center" style={{ background: LIGHT_BLUE_BG }}>
      <div className="text-center"><div className="w-12 h-12 border-4 border-t-transparent rounded-full animate-spin mx-auto mb-4" style={{ borderColor: AZ_GOLD, borderTopColor: "transparent" }} /><p style={{ color: AZ_BLUE }}>Loading...</p></div>
    </div>
  );

  return (
    <div className="min-h-screen" style={{ background: LIGHT_BLUE_BG }}>
      <div className="py-6" style={{ background: `linear-gradient(135deg, ${AZ_BLUE} 0%, ${AZ_RED} 100%)` }}>
        <div className="max-w-6xl mx-auto px-4">
          <h1 className="text-2xl font-bold text-center text-white" style={{ textShadow: "2px 2px 4px rgba(0,0,0,0.5)" }}>360° Review Results</h1>
        </div>
      </div>
      <main className="max-w-6xl mx-auto px-4 py-8">
        <div className="mb-6 flex justify-between items-center">
          <Link to="/demolay-review" className="px-4 py-2 rounded-lg font-semibold text-white" style={{ background: AZ_BLUE }}>← Back to Members</Link>
          <button onClick={handleLogout} className="px-4 py-2 rounded-lg font-semibold text-white" style={{ background: AZ_RED }}>Logout</button>
        </div>

        <div className="p-6 rounded-xl mb-6" style={{ background: "white" }}>
          <p className="font-semibold" style={{ color: AZ_BLUE }}>Logged in as: {auth.name} ({auth.email})</p>
          <p className="text-sm" style={{ color: AZ_COPPER }}>{isDad ? "Dad Account - Full Results View" : "Youth Officer - Your Reviews Only"}</p>
        </div>

        <div className="p-6 rounded-xl mb-6" style={{ background: "white" }}>
          <h2 className="text-xl font-bold mb-4" style={{ color: AZ_BLUE }}>Average Ratings by Member</h2>
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr style={{ background: AZ_BLUE }}>
                  <th className="p-3 text-left text-white font-semibold">Member</th>
                  <th className="p-3 text-center text-white font-semibold">Reviews</th>
                  <th className="p-3 text-center text-white font-semibold">Leadership</th>
                  <th className="p-3 text-center text-white font-semibold">Teamwork</th>
                  <th className="p-3 text-center text-white font-semibold">Attendance</th>
                  <th className="p-3 text-center text-white font-semibold">Punctuality</th>
                  <th className="p-3 text-center text-white font-semibold">Motivation</th>
                  <th className="p-3 text-center text-white font-semibold">Ritual</th>
                  <th className="p-3 text-center text-white font-semibold">Initiative</th>
                  <th className="p-3 text-center text-white font-semibold">Planning</th>
                  <th className="p-3 text-center text-white font-semibold">Overall</th>
                </tr>
              </thead>
              <tbody>
                {getAveragesByMember().map(m => (
                  <tr key={m.id} className="border-b" style={{ borderColor: "#e5e5e5" }}>
                    <td className="p-3"><div className="font-semibold" style={{ color: AZ_BLUE }}>{m.name}</div><div className="text-sm" style={{ color: AZ_COPPER }}>{m.title}</div></td>
                    <td className="p-3 text-center font-semibold" style={{ color: AZ_BLUE }}>{m.count}</td>
                    <td className="p-3 text-center font-semibold text-slate-900">{m.leadership}</td>
                    <td className="p-3 text-center font-semibold text-slate-900">{m.teamwork}</td>
                    <td className="p-3 text-center font-semibold text-slate-900">{m.attendance}</td>
                    <td className="p-3 text-center font-semibold text-slate-900">{m.punctuality}</td>
                    <td className="p-3 text-center font-semibold text-slate-900">{m.motivation}</td>
                    <td className="p-3 text-center font-semibold text-slate-900">{m.ritualWork}</td>
                    <td className="p-3 text-center font-semibold text-slate-900">{m.initiative}</td>
                    <td className="p-3 text-center font-semibold text-slate-900">{m.planning}</td>
                    <td className="p-3 text-center font-bold" style={{ color: AZ_BLUE }}>{m.overall}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>
    </div>
  );
}